  1→<script lang="ts">
  2→	import { onMount } from 'svelte';
  3→
  4→	export let containerName: string;
  5→	export let onClose: () => void;
  6→
  7→	const iframeSrc = `/ide/${containerName}/`;
  8→
  9→	type ConnectionStatus = 'loading' | 'connected' | 'error';
 10→	let status: ConnectionStatus = 'loading';
 11→
 12→	function handleIframeLoad(): void {
 13→		status = 'connected';
 14→	}
 15→
 16→	function handleIframeError(): void {
 17→		status = 'error';
 18→	}
 19→
 20→	// Check reachability via fetch as a belt-and-suspenders approach
 21→	onMount(() => {
 22→		const controller = new AbortController();
 23→		fetch(iframeSrc, { signal: controller.signal, method: 'HEAD' })
 24→			.then((res) => {
 25→				if (!res.ok) status = 'error';
 26→			})
 27→			.catch(() => {
 28→				// Ignore abort errors on cleanup; iframe load/error handles it
 29→			});
 30→		return () => controller.abort();
 31→	});
 32→</script>
