 13→
 14→	export let data: PageData;
 15→
 16→	$: session = data.session;
 17→	$: initialEntries = data.feedEntries ?? [];
 18→	$: containerName = data.containerName ?? null;
 19→
 20→	let showVSCodeOverlay = false;
 21→
 22→	// Subscribe to SSE stream for live updates (non-terminal sessions)
 23→	let stream: SessionStream | null = null;
 24→	let liveEntries: FeedEntry[] = [];
 25→	let unsubStream: (() => void) | null = null;
 26→
 27→	$: {
 28→		unsubStream?.();
 29→		liveEntries = [];
 30→		if (session && session.type !== 'terminal') {
 31→			stream = createSessionStream(session.id);
 32→			unsubStream = stream.subscribe((state) => {
 33→				liveEntries = state.entries;
 34→			});
 35→		} else {
 36→			stream?.destroy();
 37→			stream = null;
 38→			unsubStream = null;
 39→		}
 40→	}
 41→
 42→	$: allEntries = [...initialEntries, ...liveEntries];
 43→	$: isRunning = session?.status === 'running';
 44→
 45→	async function handleSubmit(event: CustomEvent<string>): Promise<void> {
 46→		if (!session) return;
 47→		await fetch(`/api/sessions/${session.id}/input`, {
 48→			method: 'POST',
 49→			headers: { 'Content-Type': 'application/json' },
 50→			body: JSON.stringify({ content: event.detail })
 51→		});
 52→	}
 53→
 54→	const quickCommands = ['git status', 'git log --oneline -5', 'ls -la', 'pwd'];
 55→
 56→	onDestroy(() => {
 57→		unsubStream?.();
 58→		stream?.destroy();
 59→	});
 60→</script>
