  1→<script lang="ts">
  2→	import type { Container } from '$lib/types/container.js';
  3→	import StatusPill from './StatusPill.svelte';
  4→	import VSCodeOverlay from './VSCodeOverlay.svelte';
  5→
  6→	export let container: Container;
  7→
  8→	type Tab = 'overview' | 'devcontainer' | 'env' | 'ports';
  9→	let activeTab: Tab = 'overview';
 10→	let showVSCodeOverlay = false;
 11→
 12→	// Env editing state
 13→	let newEnvKey = '';
 14→	let newEnvValue = '';
 15→	let envError = '';
 16→
 17→	// Local copy of env vars for editing
 18→	let envVars: Record<string, string> = { ...(container.config.env ?? {}) };
 19→
 20→	// Start/stop/action state
 21→	let actionLoading = false;
 22→	let actionError = '';
 23→
 24→	async function handleStart(): Promise<void> {
 25→		actionLoading = true;
 26→		actionError = '';
 27→		try {
 28→			const res = await fetch(`/api/containers/${container.id}/start`, { method: 'POST' });
 29→			if (!res.ok) {
 30→				const body = await res.json();
 31→				actionError = body.error ?? 'Failed to start container';
 32→			} else {
 33→				const updated: Container = await res.json();
 34→				container = updated;
 35→			}
 36→		} catch {
 37→			actionError = 'Network error';
 38→		} finally {
 39→			actionLoading = false;
 40→		}
 41→	}
 42→
 43→	async function handleStop(): Promise<void> {
 44→		actionLoading = true;
 45→		actionError = '';
 46→		try {
 47→			const res = await fetch(`/api/containers/${container.id}/stop`, { method: 'POST' });
 48→			if (!res.ok) {
 49→				const body = await res.json();
 50→				actionError = body.error ?? 'Failed to stop container';
 51→			} else {
 52→				const updated: Container = await res.json();
 53→				container = updated;
 54→			}
 55→		} catch {
 56→			actionError = 'Network error';
 57→		} finally {
 58→			actionLoading = false;
 59→		}
 60→	}
 61→
 62→	function addEnvVar(): void {
 63→		const key = newEnvKey.trim();
 64→		const value = newEnvValue.trim();
 65→		if (!key) {
 66→			envError = 'Key is required';
 67→			return;
 68→		}
 69→		envError = '';
 70→		envVars = { ...envVars, [key]: value };
 71→		newEnvKey = '';
 72→		newEnvValue = '';
 73→	}
 74→
 75→	function removeEnvVar(key: string): void {
 76→		const updated = { ...envVars };
 77→		delete updated[key];
 78→		envVars = updated;
 79→	}
 80→
 81→	$: devcontainerJson = JSON.stringify(
 82→		{
 83→			image: container.config.image,
 84→			containerEnv: container.config.env,
 85→			forwardPorts: container.config.ports,
 86→			mounts: container.config.mounts,
 87→			customizations: container.config.extensions?.length
 88→				? { vscode: { extensions: container.config.extensions } }
 89→				: undefined,
 90→			postCreateCommand: container.config.postCreateCommand
 91→		},
 92→		null,
 93→		2
 94→	);
 95→
 96→	$: ports = container.config.ports ?? [];
 97→	$: repoUrl = container.config.repoUrl ?? null;
 98→</script>
