 1→import type { PageLoad } from './$types';
 2→import type { Session } from '$lib/types/session.js';
 3→import type { FeedEntry } from '$lib/types/feed.js';
 4→import type { Container } from '$lib/types/container.js';
 5→
 6→export interface SessionPageData {
 7→	session: Session | null;
 8→	feedEntries: FeedEntry[];
 9→	containerName: string | null;
10→	error: string | null;
11→}
12→
13→export async function _load(id: string, fetchFn: typeof fetch): Promise<SessionPageData> {
14→	try {
15→		const res = await fetchFn(`/api/sessions/${id}`);
16→		if (res.status === 404) {
17→			return {
18→				session: null,
19→				feedEntries: [],
20→				containerName: null,
21→				error: `Session '${id}' not found`
22→			};
23→		}
24→		if (!res.ok) {
25→			return {
26→				session: null,
27→				feedEntries: [],
28→				containerName: null,
29→				error: `Failed to load session (${res.status})`
30→			};
31→		}
32→		const detail: { session: Session; feedEntries: FeedEntry[] } = await res.json();
33→
34→		// Fetch container name for VS Code overlay
35→		let containerName: string | null = null;
36→		try {
37→			const containerRes = await fetchFn(`/api/containers/${detail.session.containerId}`);
38→			if (containerRes.ok) {
39→				const container: Container = await containerRes.json();
40→				containerName = container.name ?? null;
41→			}
42→		} catch {
43→			// Container name is optional — don't fail the page load
44→		}
45→
46→		return {
47→			session: detail.session,
48→			feedEntries: detail.feedEntries,
49→			containerName,
50→			error: null
51→		};
52→	} catch {
53→		return {
54→			session: null,
55→			feedEntries: [],
56→			containerName: null,
57→			error: 'Network error loading session'
58→		};
59→	}
60→}
61→
62→export const load: PageLoad = async ({ params, fetch }) => {
63→	return _load(params.id, fetch);
64→};
