  4→type MockResponse = {
  5→	ok: boolean;
  6→	status: number;
  7→	json: () => Promise<unknown>;
  8→};
  9→
 10→function makeFetch(responses: Record<string, MockResponse>): typeof fetch {
 11→	return async (url: string | URL | Request): Promise<Response> => {
 12→		const key = typeof url === 'string' ? url : url.toString();
 13→		const resp = responses[key];
 14→		if (!resp) throw new Error(`Unexpected fetch: ${key}`);
 15→		return resp as unknown as Response;
 16→	};
 17→}
